import {describe, it, expect, beforeEach, afterEach} from 'vitest';
import {writeFileSync, mkdirSync, chmodSync} from 'node:fs';
import {join} from 'node:path';
import {performDo} from '../src/do.js';
import {NullHarness} from '../src/harness.js';
import {
	PiHarness,
	piSessionDir,
	PI_SESSION_DIRNAME,
} from '../src/pi-harness.js';
import {
	makeScratch,
	seedRepoWithArbiter,
	existsOnArbiterMain,
	gitEnv,
	type Scratch,
} from './helpers/gitRepo.js';

/**
 * `do --watch` tests (slice `do-watch`) — the live observer that tails the pi
 * session `.jsonl`. Two concerns proven here against REAL git + a stubbed pi
 * CLI (house style: throwaway checkout + local `--bare` arbiter + a pi stub that
 * edits a file AND writes a session log, no real model):
 *
 *   - `--watch` + the NULL harness ERRORS clearly (it requires pi) BEFORE any
 *     git transition;
 *   - `--watch` is a READ-ONLY OBSERVER: the run's outcome is identical to a
 *     non-watch run, AND the tailed high-signal events are surfaced live.
 *
 * It drives real git against a `--bare` arbiter AND writes `main` (the
 * autonomous surfacing), so it lives in the non-parallel (sequential) project
 * alongside `do.test.ts`.
 */

let scratch: Scratch;
beforeEach(() => {
	scratch = makeScratch('agent-runner-do-watch-');
});
afterEach(() => {
	scratch.cleanup();
});

const ARBITER = 'arbiter';

/**
 * An executable pi-CLI stub for the watch path. Honours `--session-dir`: it
 * EDITS a file in the worktree (so the completion commit is non-empty) and
 * writes a small session `.jsonl` event log (tool_start + assistant message_end
 * + agent_end) into the session dir — exactly what the tailer surfaces.
 */
function writeWatchPiStub(): string {
	const bin = join(scratch.root, 'pi-watch-stub.sh');
	const script = [
		'#!/usr/bin/env bash',
		'cat > /dev/null', // consume the prompt on stdin.
		'session_dir=""',
		'prev=""',
		'for a in "$@"; do',
		'  if [ "$prev" = "--session-dir" ]; then session_dir="$a"; fi',
		'  prev="$a"',
		'done',
		// Edit a file so the runner has something to commit.
		"printf 'work done\\n' > agent-output.txt",
		// Write the session .jsonl the observer tails.
		'if [ -n "$session_dir" ]; then',
		'  mkdir -p "$session_dir"',
		'  log="$session_dir/session.jsonl"',
		`  printf '%s\\n' '{"type":"tool_start","tool":"edit"}' >> "$log"`,
		`  printf '%s\\n' '{"type":"message_end","message":{"role":"assistant","content":[{"type":"text","text":"all set"}]}}' >> "$log"`,
		`  printf '%s\\n' '{"type":"agent_end"}' >> "$log"`,
		'fi',
		'exit 0',
	].join('\n');
	writeFileSync(bin, script + '\n');
	chmodSync(bin, 0o755);
	return bin;
}

describe('do --watch — requires the pi harness (errors on null)', () => {
	it('errors CLEARLY when --watch is passed with the null harness, BEFORE any git transition', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);

		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			verify: 'exit 0',
			harness: new NullHarness(),
			agentCmd: 'true',
			watch: true,
			env: gitEnv(),
		});

		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('usage-error');
		expect(result.message).toMatch(/--watch/);
		expect(result.message).toMatch(/pi/);
		// NO git transition happened: still in backlog, never claimed.
		expect(existsOnArbiterMain(repo, 'backlog', 'alpha')).toBe(true);
		expect(existsOnArbiterMain(repo, 'in-progress', 'alpha')).toBe(false);
	});
});

describe('do --watch — READ-ONLY observer (outcome unchanged, events surfaced)', () => {
	it('completes identically to a non-watch run AND surfaces the tailed high-signal events', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		const piBin = writeWatchPiStub();

		const surfaced: string[] = [];
		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: 'exit 0',
			harness: new PiHarness({piBin}),
			watch: true,
			watchSink: (line) => surfaced.push(line),
			color: false,
			env: gitEnv(),
		});

		// Outcome is the SAME as a normal `do` run (observer changed nothing).
		expect(result.exitCode).toBe(0);
		expect(result.outcome).toBe('completed');
		expect(existsOnArbiterMain(repo, 'done', 'alpha')).toBe(true);

		// The agent's edit landed (the runner committed it with the done-move).
		expect(
			existsOnArbiterMain(repo, 'done', 'alpha') && surfaced.includes('▶ edit'),
		).toBe(true);

		// The tailer surfaced the high-signal events from the session .jsonl,
		// skipping the rest (parity with ar-run.sh --watch).
		expect(surfaced).toContain('▶ edit');
		expect(surfaced).toContain('all set');
		expect(surfaced).toContain('✓ agent finished');
	});

	it('a do run WITHOUT --watch surfaces nothing (the observer is opt-in)', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		const piBin = writeWatchPiStub();

		const surfaced: string[] = [];
		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: 'exit 0',
			harness: new PiHarness({piBin}),
			// no watch flag
			watchSink: (line) => surfaced.push(line),
			env: gitEnv(),
		});

		expect(result.outcome).toBe('completed');
		expect(existsOnArbiterMain(repo, 'done', 'alpha')).toBe(true);
		// No --watch ⇒ no tailer ⇒ nothing surfaced (byte-identical behaviour).
		expect(surfaced).toEqual([]);
		// The session dir still exists (pi wrote it) — but it was NOT tailed.
		expect(piSessionDir(repo)).toContain(PI_SESSION_DIRNAME);
	});
});

edits.oldText:
/**
 * Parse ONE pi session `.jsonl` line and format it into the high-signal line to
 * surface — or `undefined` to SKIP it (the `else empty` arm of the `jq`
 * filter). This is the pure, unit-testable core of the parity:
 *
 *   - `tool_start`                       → `▶ <tool>` (cyan; `tool` defaults to
 *                                          `tool` when absent, like `.tool // "tool"`)
 *   - `message_end` + assistant role     → the assistant text (concatenated text
 *                                          parts, like the `jq` `.content[]` select)
 *   - `agent_end`                        → `✓ agent finished` (green)
 *   - anything else / blank / malformed  → `undefined` (skipped — never throws).
 *
 * Malformed JSON is skipped (not thrown): a partially-written trailing line in a
 * growing log must not crash the observer.
 */
export function formatWatchEvent(
	line: string,
	color: boolean,
): string | undefined {
	const trimmed = line.trim();
	if (trimmed === '') {
		return undefined;
	}
	let event: unknown;
	try {
		event = JSON.parse(trimmed);
	} catch {
		// A half-written trailing line in a growing log — skip, never throw.
		return undefined;
	}
	if (typeof event !== 'object' || event === null) {
		return undefined;
	}
	const e = event as Record<string, unknown>;
	switch (e.type) {
		case 'tool_start': {
			const tool =
				typeof e.tool === 'string' && e.tool !== '' ? e.tool : 'tool';
			return paint(`▶ ${tool}`, color, CYAN);
		}
		case 'message_end': {
			const message = e.message as Record<string, unknown> | undefined;
			if (!message || message.role !== 'assistant') {
				return undefined;
			}
			const text = assistantText(message.content);
			return text === '' ? undefined : text;
		}
		case 'agent_end':
			return paint('✓ agent finished', color, GREEN);
		default:
			return undefined;
	}
}

/**
 * Extract the assistant text from a `message_end` `message.content`, mirroring
 * the `jq` `(.message.content[]? | select(.type=="text") | .text)` projection:
 * concatenate the `text` of every `{type:"text"}` part. Tolerates a plain-string
 * content (some shapes carry the text directly) and non-array/absent content.
 */
function assistantText(content: unknown): string {
	if (typeof content === 'string') {
		return content;
	}
	if (!Array.isArray(content)) {
		return '';
	}
	const parts: string[] = [];
	for (const part of content) {
		if (
			typeof part === 'object' &&
			part !== null &&
			(part as Record<string, unknown>).type === 'text' &&
			typeof (part as Record<string, unknown>).text === 'string'
		) {
			parts.push((part as Record<string, unknown>).text as string);
		}
	}
	return parts.join('');
}

edits.newText:
/**
 * A structural view of the pi SESSION-LOG records we classify. It mirrors the
 * `@earendil-works/pi-coding-agent` `SessionEntry` / `SessionMessageEntry`
 * shapes (`type:"message"` with a nested `message.role` + `message.content`) but
 * is declared locally so the observer needs no runtime dependency on that
 * package's (heavy) type tree — agent-runner does not otherwise depend on it.
 * The content blocks are read defensively (like pi-remote's reference parser,
 * which casts them via `as any`): a content part may be a `text`, a `thinking`,
 * or a `toolCall` (whose name is `name` OR `toolName`), or the whole content may
 * be a plain string.
 */
interface SessionLogRecord {
	type?: unknown;
	message?: {
		role?: unknown;
		content?: unknown;
	};
}

/** The green `✓ agent finished` line, emitted on PROCESS EXIT (not a log event). */
export function finishedLine(color: boolean): string {
	return paint('✓ agent finished', color, GREEN);
}

/**
 * Parse ONE pi SESSION-LOG `.jsonl` line and return the high-signal lines to
 * surface — or `[]` to SKIP it. This is the pure, unit-testable classifier,
 * mirroring pi-remote's `session-pool.ts` block walk:
 *
 *   - a `{type:"message", message:{role:"assistant", content}}` record → for each
 *     `content[]` part: a `text` part yields its text (parts concatenated into
 *     ONE line, like the old `jq` `.content[]` select); a `toolCall` part yields
 *     `▶ <name>` (cyan; `name` OR `toolName`, defaulting to `tool`); a `thinking`
 *     part (and anything else) is skipped. A plain-string `content` yields one
 *     text line.
 *   - everything else (`session`/`model_change`/`thinking_level_change`, user
 *     messages, tool results, blank/malformed lines) → `[]` (skipped).
 *
 * "Finished" is NOT a record here — the session log has no `agent_end`; the
 * tailer emits {@link finishedLine} on process exit instead.
 *
 * Malformed JSON is skipped (not thrown): a partially-written trailing line in a
 * growing log must not crash the observer.
 */
export function formatWatchEvent(line: string, color: boolean): string[] {
	const trimmed = line.trim();
	if (trimmed === '') {
		return [];
	}
	let event: unknown;
	try {
		event = JSON.parse(trimmed);
	} catch {
		// A half-written trailing line in a growing log — skip, never throw.
		return [];
	}
	if (typeof event !== 'object' || event === null) {
		return [];
	}
	const record = event as SessionLogRecord;
	if (record.type !== 'message') {
		return [];
	}
	const message = record.message;
	if (!message || message.role !== 'assistant') {
		// Skip user turns, tool results, and any non-assistant message.
		return [];
	}
	return assistantLines(message.content, color);
}

/**
 * Walk an assistant `message.content` into the lines to surface, mirroring
 * pi-remote's `session-pool.ts` reference parser. The `text` parts are
 * concatenated into a SINGLE leading line (so a multi-part assistant turn reads
 * as one sentence, as `ar-run.sh --watch` showed it); each `toolCall` part adds a
 * `▶ <name>` line after it. A plain-string content yields the single text line.
 * `thinking` parts and any other block type are skipped.
 */
function assistantLines(content: unknown, color: boolean): string[] {
	if (typeof content === 'string') {
		return content === '' ? [] : [content];
	}
	if (!Array.isArray(content)) {
		return [];
	}
	const lines: string[] = [];
	const textParts: string[] = [];
	for (const part of content) {
		if (typeof part !== 'object' || part === null) {
			continue;
		}
		const p = part as Record<string, unknown>;
		if (p.type === 'text' && typeof p.text === 'string') {
			textParts.push(p.text);
		} else if (p.type === 'toolCall') {
			const name =
				(typeof p.name === 'string' && p.name !== '' && p.name) ||
				(typeof p.toolName === 'string' && p.toolName !== '' && p.toolName) ||
				'tool';
			lines.push(paint(`▶ ${name}`, color, CYAN));
		}
		// `thinking` and any other block type are skipped.
	}
	const text = textParts.join('');
	return text === '' ? lines : [text, ...lines];
}

